import React, { useState, useEffect } from 'react';
import ProductCard from '@/components/ProductCard.tsx';
import { cn } from '@/lib/utils.ts';

// Define a simple Product interface
interface Product {
  id: string;
  name: string;
  description: string;
  price: number;
  imageUrl: string;
}

// Utility function to generate random product data
const generateRandomProducts = (count: number): Product[] => {
  const products: Product[] = [];
  const adjectives = ['Stylish', 'Modern', 'Classic', 'Elegant', 'Durable', 'Smart', 'Compact', 'Premium', 'Ergonomic', 'Versatile'];
  const nouns = ['Chair', 'Table', 'Lamp', 'Sofa', 'Desk', 'Shelf', 'Cabinet', 'Bed', 'Rug', 'Vase', 'Mirror', 'Clock'];

  for (let i = 1; i <= count; i++) {
    const randomAdjective = adjectives[Math.floor(Math.random() * adjectives.length)];
    const randomNoun = nouns[Math.floor(Math.random() * nouns.length)];
    const name = `${randomAdjective} ${randomNoun} ${i}`;
    const price = parseFloat((Math.random() * (500 - 50) + 50).toFixed(2)); // Price between 50 and 500
    const description = `A high-quality ${name.toLowerCase()} designed for comfort and style. Perfect for any modern home or office.`;
    const imageUrl = `https://picsum.photos/seed/${i + 100}/400/300`; // Unique image for each product

    products.push({
      id: `prod-${i}`,
      name,
      description,
      price,
      imageUrl,
    });
  }
  return products;
};

const ProductsPage: React.FC = () => {
  const [products, setProducts] = useState<Product[]>([]);

  useEffect(() => {
    // Generate 30 random products when the component mounts
    const generatedProducts = generateRandomProducts(30);
    setProducts(generatedProducts);
  }, []);

  return (
    <div className="container mx-auto py-8 px-4">
      <h1 className="text-4xl font-bold text-center mb-8">Our Products</h1>
      <div className="grid grid-cols-1 sm:grid-cols-2 md:grid-cols-3 lg:grid-cols-4 gap-6">
        {products.map((product) => (
          <ProductCard key={product.id} product={product} />
        ))}
      </div>
    </div>
  );
};

export default ProductsPage;
